import React from "react"
import { graphql, StaticQuery } from "gatsby"
import { GithubLogo, Rss, Envelope, Globe } from "@phosphor-icons/react"

interface FooterData {
  site: {
    siteMetadata: {
      author: string
    }
  }
}

const socialLinks = [
  {
    href: "https://github.com/ximing",
    label: "GitHub",
    Icon: () => <GithubLogo weight="duotone" size={20} />,
  },
  {
    href: "https://www.zhihu.com/people/xi-ming-52/activities",
    label: "知乎",
    Icon: () => <span className="text-xs font-bold">Z</span>,
  },
  {
    href: "https://dev.to/ximing",
    label: "Dev.to",
    Icon: () => <span className="text-xs font-bold">D</span>,
  },
  {
    href: "https://www.codewars.com/users/ximing",
    label: "Codewars",
    Icon: () => <span className="text-xs font-bold">C</span>,
  },
]

function FooterContent({ data }: { data: FooterData }): React.ReactElement {
  const { author } = data.site.siteMetadata
  const currentYear = new Date().getFullYear()

  return (
    <footer className="w-full bg-background-secondary">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
          {/* Left: Social Links */}
          <div className="flex items-center gap-4">
            {socialLinks.map(({ href, label, Icon }) => (
              <a
                key={label}
                href={href}
                target="_blank"
                rel="external nofollow noopener noreferrer"
                className="group flex items-center justify-center w-10 h-10 rounded-lg bg-secondary text-foreground-secondary hover:text-primary hover:bg-primary-subtle transition-all duration-200"
                aria-label={label}
                title={label}
              >
                <span className="transition-transform duration-200 group-hover:scale-110">
                  <Icon />
                </span>
              </a>
            ))}
          </div>

          {/* Right: RSS and Copyright */}
          <div className="flex flex-col sm:flex-row items-center gap-4 sm:gap-6 text-sm text-foreground-secondary">
            <a
              href="/rss.xml"
              target="_blank"
              className="group flex items-center gap-2 hover:text-primary transition-colors duration-200"
              aria-label="RSS Feed"
            >
              <Rss weight="duotone" size={16} className="transition-transform duration-200 group-hover:scale-110" />
              <span>RSS</span>
            </a>
            <span className="hidden sm:inline text-text-muted">·</span>
            <span>
              © {currentYear} {author}
            </span>
          </div>
        </div>

        {/* Bottom: 备案号和联系方式 */}
        <div className="mt-6 flex flex-col sm:flex-row items-center justify-center gap-2 sm:gap-6 text-xs text-foreground-secondary">
          <a
            href="mailto:morningxm@hotmail.com"
            className="flex items-center gap-1 hover:text-primary transition-colors duration-200"
            aria-label="邮箱联系方式"
          >
            <Envelope size={12} />
            <span>morningxm@hotmail.com</span>
          </a>
          <span className="hidden sm:inline text-text-muted">·</span>
          <span className="flex items-center gap-1">
            <Globe size={12} />
            <span>京ICP备16033518号-6</span>
          </span>
        </div>
      </div>
    </footer>
  )
}

function Footer(): React.ReactElement {
  return (
    <StaticQuery
      query={footerQuery}
      render={(data: FooterData) => <FooterContent data={data} />}
    />
  )
}

const footerQuery = graphql`
  query LayoutFooterQuery {
    site {
      siteMetadata {
        author
      }
    }
  }
`

export default Footer
